function maxValueAfterOperations(grid) {
    let ans = 0;
    while (grid.length) {
        let maxVal = 0;
        let maxRow = -1;

        grid.forEach((row, i) => {
            let rowMax = Math.max(...row);
            if (rowMax > maxVal) {
                maxVal = rowMax;
                maxRow = i;
            }
            grid[i] = row.filter(e => e !== rowMax);
        });

        ans += maxVal;
        if (!grid[maxRow].length) {
            grid.splice(maxRow, 1);
        }
    }

    return ans;
}
```


    - Loop until 'grid' becomes empty.
- Search for the greatest element in each row and delete any of them if there's a tie. Keep track of the maximum of deleted elements and the respective row number.
- Add the maximum of deleted elements to 'ans'.
- If the row with initially found maximum becomes empty, remove that row from 'grid'.
- Finally, return the sum of all maximum deleted elements 'ans'.

solutionCode.java:
    ```java
int maxValueAfterOperations(int[][] grid) {
    int ans = 0;
    while (grid.length != 0) {
        int maxVal = 0, maxRow = -1;

        for (int i = 0; i < grid.length; ++i) {
            int rowMax = Arrays.stream(grid[i]).max().getAsInt();
            if (rowMax > maxVal) {
                maxVal = rowMax;
                maxRow = i;
            }
            grid[i] = Arrays.stream(grid[i]).filter(e -> e != rowMax).toArray();
        }

        ans += maxVal;
        if (grid[maxRow].length == 0) {
            grid = Arrays.stream(grid).filter(row -> row.length != 0).toArray(int[][]::new);
        }
    }

    return ans;
}
```


    - Loop until 'grid' becomes empty.
- Search for the greatest element in each row and delete any of them if there's a tie. Keep track of the maximum of deleted elements and the respective row number.
- Add the maximum of deleted elements to 'ans'.
- If the row with initially found maximum becomes empty, remove that row from 'grid'.
- Finally, return the sum of all maximum deleted elements 'ans'.
